css:
.customer {
       /*text-align: center;*/
       font-size: 0; /* eliminate inline-block spacing gaps */
       width: 100%;
   }

   .customer-left,
   .customer-right {
       display: inline-block;
       width: 48%; /* adjust for spacing */
       vertical-align: top;
       font-size: 14px; /* restore font size */
       text-align: left;
   }

   .customer-left {
     text-align:left;
   }

   .customer-right {
       text-align: right; /* center inner children horizontally */
       margin-left : 4px;
   }

   .customer-right-left,
   .customer-right-right {
       display: inline-block;
       width: 48%; /* same width for equal spacing */
       vertical-align: top;
       font-size: 14px;
   }
   .customer-right-left{
       text-align:left;
   }
   .customer-right-right{
       text-align:right;
   }

   .customer-right-left div,
   .customer-right-right div {
       display: block; /* stack lines vertically */
   }
